#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; char s[1005];
        scanf("%d", &N);
        scanf("%s", s);
        int half = N / 2;
        int equal = 1;
        for (int i = 0; i < half; ++i) {
            if (s[i] != s[i + half]) { equal = 0; break; }
        }
        printf(equal ? "YES\n" : "NO\n");
    }
    return 0;
}

